21	class ResumeDriver
22	{
23	public:
24	  static constexpr uint8_t kData0      = 0x04;
25	  static constexpr uint8_t kData1      = 0x05;
26	  static constexpr uint8_t kDmcontrol  = 0x10;
27	  static constexpr uint8_t kDmstatus   = 0x11;
28	  static constexpr uint8_t kAbstractcs = 0x16;
29	  static constexpr uint8_t kCommand    = 0x17;
30	
31	  static constexpr uint16_t kCsrDpc      = 0x7B1;
32	  static constexpr uint16_t kCsrMstatus  = 0x300;
33	  static constexpr uint16_t kCsrMtvec    = 0x305;
34	  static constexpr uint16_t kCsrMcycle   = 0xB00;
35	  static constexpr uint16_t kCsrMinstret = 0xB02;
36	  static constexpr uint16_t kCsrVstart   = 0x008;
37	  static constexpr uint16_t kCsrVxsat    = 0x009;
38	  static constexpr uint16_t kCsrVxrm     = 0x00A;
39	  static constexpr uint16_t kCsrVcsr     = 0x00F;
40	  static constexpr uint16_t kCsrVtype    = 0xC21;
41	  static constexpr uint16_t kCsrVl       = 0xC20;
42	
43	  static constexpr uint32_t kDmcontrolDmactive  = 1u << 0;
44	  static constexpr uint32_t kDmcontrolResumereq = 1u << 30;
45	  static constexpr uint32_t kDmcontrolHaltreq   = 1u << 31;
46	
47	  static constexpr uint32_t kDmstatusAllhalted    = 1u << 9;
48	  static constexpr uint32_t kDmstatusAllresumeack = 1u << 17;
49	
50	  static constexpr uint32_t kAbstractcsBusy        = 1u << 12;
51	  static constexpr uint32_t kAbstractcsCmderrMask  = 0x7u << 8;
52	
53	  static constexpr unsigned kPollIterations = kDmiPollIterations;
54	
55	  explicit ResumeDriver(DmiBus& bus)
56	      : bus_{bus}
57	  {}
58	
59	  void resume(const hybrid_state_v1& state)
60	  {
61	    if (state.magic != HYBRID_STATE_MAGIC)
62	      throw std::runtime_error("ResumeDriver::resume: bad magic");
63	    if (state.version != HYBRID_STATE_VERSION)
64	      throw std::runtime_error("ResumeDriver::resume: unsupported version");
65	
66	    // dmactive must transition 0->1 in its own write before any other
67	    // DMCONTROL bit is honored (RISC-V Debug Spec).
68	    bus_.write(kDmcontrol, kDmcontrolDmactive);
69	    request_halt();
70	    poll_until_set(bus_, kDmstatus, kDmstatusAllhalted, "ResumeDriver halt");
71	
72	    // mstatus: enable FS / VS so the following FPR / V abstract writes are
73	    // accepted (FS or VS == Off disables the extension and the hart NACKs
74	    // the writes). Single write covers both extensions when present.
75	    const bool fp_needs_fs = (state.flags & HYBRID_FLAG_FP)
76	                          && (state.mstatus & 0x6000u);  // FS = 13:14
77	    const bool v_needs_vs  = (state.flags & HYBRID_FLAG_V)
78	                          && (state.mstatus & 0x600u);   // VS =  9:10
79	    if (fp_needs_fs || v_needs_vs)
80	      write_csr_abstract_or_pb(kCsrMstatus, state.mstatus);
81	
82	    // FPR restore (requires mstatus.FS enabled above).
83	    if (state.flags & HYBRID_FLAG_FP) {
84	      for (uint16_t i = 0; i < 32; ++i)
85	        write_64bit_register(regno_fpr(i), state.fpr[i]);
86	    }
87	
88	    // Tier-A V CSR restore (before GPRs: PB fallback uses x5 as scratch;
89	    // the GPR loop overwrites x5 afterward so state is preserved).
90	    if (state.flags & HYBRID_FLAG_V) {
91	      // Tier-B: vtype+vl via vsetvl x0,x5,x6 in PB.
92	      // Direct csrrw to vtype sets vill; vl is read-only. Stage operands in
93	      // scratch GPRs x5(vl) and x6(vtype) then let vsetvl set both atomically.
94	      // x5/x6 are overwritten by the GPR loop below, so no leakage.
95	      write_64bit_register(regno_gpr(5), state.vl);
96	      write_64bit_register(regno_gpr(6), state.vtype);
97	      const std::array<uint32_t, 1> pb_vsetvl = { encode_vsetvl(0, 5, 6) };
98	      exec_progbuf(bus_, std::span<const uint32_t>{pb_vsetvl});
99	      // vstart must come AFTER vsetvl: vsetvl resets vstart to 0.
100	      write_csr_abstract_or_pb(kCsrVstart, state.vstart);
101	      write_csr_abstract_or_pb(kCsrVxsat,  state.vxsat);
102	      write_csr_abstract_or_pb(kCsrVxrm,   state.vxrm);
103	      write_csr_abstract_or_pb(kCsrVcsr,   state.vcsr);
104	    }
105	
106	    // GPRs + DPC (after V CSRs so PB scratch x5 is safe to overwrite).
107	    for (uint16_t i = 1; i < 32; ++i)
108	      write_64bit_register(regno_gpr(i), state.gpr[i]);
109	    write_64bit_register(regno_csr(kCsrDpc), state.pc);
110	
111	    write_csr_tolerant(kCsrMtvec, state.mtvec);
112	
113	    // F-T2.4: restore mcycle/minstret so the vsim phase continues counting
114	    // from QEMU1's drain value. Without this, vsim's local counter starts
115	    // at zero and any cycles spent inside the ROI vanish at the QEMU2
116	    // boundary. PB fallback uses x5 as scratch; safe to overwrite here as
117	    // the GPR loop already ran.
118	    write_csr_abstract_or_pb(kCsrMcycle,   state.mcycle);
119	    write_csr_abstract_or_pb(kCsrMinstret, state.minstret);
120	
121	    clear_cmderr_if_set();
122	    request_resume();
123	    poll_until_set(bus_, kDmstatus, kDmstatusAllresumeack,
124	                   "ResumeDriver resume");
125	  }
126	
127	private:
128	  void request_halt()
129	  {
130	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolHaltreq);
131	  }
132	
133	  void request_resume()
134	  {
135	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolResumereq);
136	  }
137	
138	  void write_64bit_register(uint16_t regno, uint64_t value)
139	  {
140	    bus_.write(kData0, uint32_t(value & 0xffffffffu));
141	    bus_.write(kData1, uint32_t((value >> 32) & 0xffffffffu));
142	    bus_.write(kCommand,
143	               access_register_command(regno, AarSize::Bits64, /*write=*/true));
144	    poll_until_clear(bus_, kAbstractcs, kAbstractcsBusy,
145	                     "ResumeDriver write_register");
146	  }
147	
148	  // Abstract-first CSR write with Program Buffer fallback.
149	  // Tries an abstract register write; if the DM signals cmderr, clears it,
150	  // stages the value in scratch_gpr via abstract GPR write, then executes a
151	  // one-instruction PB (`csrrw x0, csr, scratch_gpr`).  scratch_gpr defaults
152	  // to x5 (t0) which the GPR restore loop overwrites later.
153	  void write_csr_abstract_or_pb(uint16_t csr, uint64_t value,
154	                                 uint8_t scratch_gpr = 5)
155	  {
156	    write_64bit_register(regno_csr(csr), value);
157	    if ((bus_.read(kAbstractcs) & kAbstractcsCmderrMask) == 0u) return;
158	    bus_.write(kAbstractcs, kAbstractcsCmderrMask);  // W1C: clear sticky error
159	    write_64bit_register(regno_gpr(scratch_gpr), value);
160	    const std::array<uint32_t, 1> pb = { encode_csrrw(0, csr, scratch_gpr) };
161	    exec_progbuf(bus_, std::span<const uint32_t>{pb});
162	  }
163	
164	  // Write a CSR-addressable register and clear any cmderr the DM raised.
165	  // Used for CSRs whose abstract-access support may be implementation
166	  // dependent; a missing CSR mirrors as a no-op rather than blocking the
167	  // remaining writes.
168	  void write_csr_tolerant(uint16_t csr, uint64_t value)
169	  {
170	    write_64bit_register(regno_csr(csr), value);
171	    clear_cmderr_if_set();
172	  }
173	
174	  // abstractcs.cmderr is sticky per the Debug Spec - a subsequent command
175	  // is rejected until the bits are W1C-cleared. We tolerate per-register
176	  // failures (e.g. unimplemented FPR/CSR Abstract access) by clearing the
177	  // error before resuming so the hart isn't left in a stuck state.
178	  void clear_cmderr_if_set()
179	  {
180	    const auto status = bus_.read(kAbstractcs);
181	    if ((status & kAbstractcsCmderrMask) != 0u)
182	      bus_.write(kAbstractcs, kAbstractcsCmderrMask);
183	  }
184	
185	  DmiBus& bus_;
186	};
