19	#ifdef __cplusplus
20	extern "C" {
21	#endif
22	
23	#define HYBRID_STATE_MAGIC   0x42594841u  // 'AHYB' little-endian
24	#define HYBRID_STATE_VERSION 1u
25	
26	#define HYBRID_FLAG_RV64 (1u << 0)
27	#define HYBRID_FLAG_FP   (1u << 1)
28	#define HYBRID_FLAG_V    (1u << 2)
