31	// which sets `NDS_VLEN 512` (-> 64 bytes per vector register). When that
32	// configured value changes, this constant must be updated in lock-step so
33	// the wire-format struct grows or shrinks to match the configured RVV width.
34	#define HYBRID_VLEN_BYTES_MAX 64
