36	// 64 PMP entries; pmpcfg slots reserved at 16 so the layout works for both
37	// RV64 (8 entries/CSR) and a future RV32 (4 entries/CSR) packing.
38	#define HYBRID_PMP_CFG_NUM  16
39	#define HYBRID_PMP_ADDR_NUM 64
