41	// All fields are naturally 8-byte aligned, so __attribute__((packed)) is
42	// unnecessary and would force unaligned access codegen. Layout is locked by
43	// the static_asserts in state_abi_check.h.
44	struct hybrid_state_v1 {
45	  uint32_t magic;
