67	  uint64_t satp;
68	
69	  uint64_t pmpcfg[HYBRID_PMP_CFG_NUM];
70	  uint64_t pmpaddr[HYBRID_PMP_ADDR_NUM];
71	
72	  uint64_t vstart;
73	  uint64_t vtype;
74	  uint64_t vl;
75	  uint64_t vlenb;
76	  uint8_t  vreg[32 * HYBRID_VLEN_BYTES_MAX];
